Here's a complete MSTest test class for `DataFetcher` covering success, failure, cancellation, and timeout scenarios:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode statusCode = HttpStatusCode.OK,
        string content = "response-body")
    {
        var handler = new FakeHandler(statusCode, content);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var (fetcher, _) = CreateFetcher(content: "hello world");

        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/error", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutViaCancellation_ThrowsTaskCanceled()
    {
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PassesCancellationTokenToHttpClient()
    {
        var (fetcher, handler) = CreateFetcher();

        await fetcher.FetchAsync("https://example.com/data", _testContext.CancellationToken);

        Assert.AreNotEqual(CancellationToken.None, handler.ReceivedToken);
    }

    // Fake HttpMessageHandler for deterministic testing
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _statusCode;
        private readonly string _content;
        private readonly TimeSpan? _delay;

        public CancellationToken ReceivedToken { get; private set; }

        public FakeHandler(
            HttpStatusCode statusCode = HttpStatusCode.OK,
            string content = "",
            TimeSpan? delay = null)
        {
            _statusCode = statusCode;
            _content = content;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            ReceivedToken = cancellationToken;

            if (_delay is { } d)
            {
                await Task.Delay(d, cancellationToken);
            }

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns used:**

- **`[Timeout]` + `TestContext.CancellationToken`** — cooperative timeout so tests don't hang indefinitely
- **`Assert.ThrowsExactlyAsync<T>`** — verifies exact exception type (not `[ExpectedException]`)
- **`FakeHandler`** — custom `HttpMessageHandler` avoids real HTTP calls and lets you control delays, status codes, and verify token forwarding
- **Pre-canceled token** — tests immediate cancellation path
- **Short `CancellationTokenSource` timeout** — simulates a caller-imposed deadline

The `FakeHandler` with a `delay` parameter is the key trick: it makes the handler await `Task.Delay(d, cancellationToken)`, so cancellation fires naturally through the same code path your production code uses.
